    const minor = this.normalizeToken(student?.minor_id, 'GENERAL');
    const pathway = this.normalizeToken(student?.pathway_id, 'P0');

    if (bucket === 'Specialization') return `SPEC-${batchToken}-SEM${semester}-${specialization}`;
