require('dotenv').config();
const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);

const slots = [
  '09:00 AM - 09:50 AM',
  '10:00 AM - 10:50 AM',
  '11:00 AM - 11:50 AM',
  '12:00 PM - 12:50 PM',
  '01:10 PM - 02:00 PM',
  '02:10 PM - 03:00 PM',
  '03:10 PM - 04:00 PM',
  '04:10 PM - 05:00 PM'
];
const days = ['Mon','Tue','Wed','Thu','Fri','Sat'];

(async()=>{
  const { data: mt, error: e1 } = await supabase.from('master_timetable').select('*');
  if (e1) throw e1;

  const target = mt.filter(r => r.course_code === 'ENG101' && r.section_name === 'K26DG');
  if (!target.length) {
    console.log('No scheduled rows found for target section in master_timetable');
    return;
  }

  const teacher = target[0].instructor_name;
  const students = Array.isArray(target[0].student_ids) ? target[0].student_ids : [];
  const studentSet = new Set(students);

  const { data: courses, error: e2 } = await supabase.from('courses').select('course_id, course_type').eq('course_id','ENG101');
  if (e2) throw e2;
  const courseType = String(courses?.[0]?.course_type || '').toLowerCase();
  const needsLab = courseType.includes('lab');

  const { data: infra, error: e3 } = await supabase.from('infrastructure').select('room_id, room_type, capacity_lecture, is_byod_ready, block_id');
  if (e3) throw e3;

  const byodNeeded = students.some(() => false); // can't infer directly here without students table; use timetable rows for byod is not stored
  const compatibleRooms = (infra||[]).filter(r => {
    const roomType = String(r.room_type || '').toLowerCase();
    const isLab = roomType.includes('lab');
    if (needsLab && !isLab) return false;
    if (!needsLab && isLab) return false;
    if (r.capacity_lecture < students.length) return false;
    return true;
  });

  const roomOcc = new Set();
  const teacherOcc = new Set();
  const studentOcc = new Set();
  for (const r of mt) {
    const time = r.time_slot;
    roomOcc.add(`${r.room_id}|${time}`);
    teacherOcc.add(`${r.instructor_name}|${time}`);
    const sids = Array.isArray(r.student_ids) ? r.student_ids : [];
    for (const sid of sids) studentOcc.add(`${sid}|${time}`);
  }

  // ignore the already placed rows for the same section to find free windows for another session
  for (const r of target) {
    const time = r.time_slot;
    roomOcc.delete(`${r.room_id}|${time}`);
    teacherOcc.delete(`${r.instructor_name}|${time}`);
    const sids = Array.isArray(r.student_ids) ? r.student_ids : [];
    for (const sid of sids) studentOcc.delete(`${sid}|${time}`);
  }

  const feasible = [];
  const blocked = [];

  for (const d of days) {
    for (const s of slots) {
      const time = `${d} ${s}`;
      if (teacherOcc.has(`${teacher}|${time}`)) {
        blocked.push({time, reason:'teacher_busy'});
        continue;
      }
      let studentBusy = false;
      for (const sid of studentSet) {
        if (studentOcc.has(`${sid}|${time}`)) { studentBusy = true; break; }
      }
      if (studentBusy) {
        blocked.push({time, reason:'student_busy'});
        continue;
      }
      const freeRooms = compatibleRooms.filter(r => !roomOcc.has(`${r.room_id}|${time}`));
      if (!freeRooms.length) {
        blocked.push({time, reason:'no_room'});
        continue;
      }
      feasible.push({time, roomCount: freeRooms.length});
    }
  }

  const reasonCounts = blocked.reduce((a,b)=>{a[b.reason]=(a[b.reason]||0)+1; return a;}, {});

  console.log('Target section:', { section:'K26DG-ENG101', teacher, studentCount: students.length, existingPlacedSessions: target.length, compatibleRoomCount: compatibleRooms.length });
  console.log('Feasible extra slots:', feasible.length);
  if (feasible.length) console.log('Sample feasible:', feasible.slice(0,8));
  console.log('Blocked reason counts:', reasonCounts);
})();
