require('dotenv').config();
const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);

const slots = [
  '09:00 AM - 09:50 AM','10:00 AM - 10:50 AM','11:00 AM - 11:50 AM','12:00 PM - 12:50 PM',
  '01:10 PM - 02:00 PM','02:10 PM - 03:00 PM','03:10 PM - 04:00 PM','04:10 PM - 05:00 PM'
];
const days = ['Mon','Tue','Wed','Thu','Fri','Sat'];

(async()=>{
  const { data: mt, error: e1 } = await supabase.from('master_timetable').select('*');
  if (e1) throw e1;

  const targetRows = mt.filter(r => r.course_code === 'ENG101' && r.section_name === 'K26DG');
  if (!targetRows.length) throw new Error('target section rows not found');

  const target = targetRows[0];
  const teacher = target.instructor_name;
  const students = Array.isArray(target.student_ids) ? target.student_ids : [];

  const { data: faculty, error: e2 } = await supabase.from('faculty').select('teacher_id,name,forbidden_slots');
  if (e2) throw e2;
  const teacherRec = (faculty||[]).find(f => f.name === teacher);
  const forbidden = new Set(Array.isArray(teacherRec?.forbidden_slots) ? teacherRec.forbidden_slots.map(String) : []);

  const { data: infra, error: e3 } = await supabase.from('infrastructure').select('room_id,room_type,capacity_lecture');
  if (e3) throw e3;
  const compatibleRooms = (infra||[]).filter(r => {
    const isLab = String(r.room_type||'').toLowerCase().includes('lab');
    if (isLab) return false; // ENG101 lecture
    return Number(r.capacity_lecture||0) >= students.length;
  });

  const roomOcc = new Set();
  const teacherOcc = new Set();
  const studentOcc = new Set();
  for (const r of mt) {
    const tk = r.time_slot;
    roomOcc.add(`${r.room_id}|${tk}`);
    teacherOcc.add(`${r.instructor_name}|${tk}`);
    const sids = Array.isArray(r.student_ids) ? r.student_ids : [];
    for (const sid of sids) studentOcc.add(`${sid}|${tk}`);
  }

  const results = [];
  for (const d of days) {
    for (const s of slots) {
      const tk = `${d} ${s}`;
      if (targetRows.some(r => r.time_slot === tk)) continue; // already used by this section

      const teacherBusy = teacherOcc.has(`${teacher}|${tk}`);
      let studentBusy = false;
      for (const sid of students) {
        if (studentOcc.has(`${sid}|${tk}`)) { studentBusy = true; break; }
      }
      const freeRoomCount = compatibleRooms.filter(r => !roomOcc.has(`${r.room_id}|${tk}`)).length;
      const forbiddenHit = forbidden.has(tk) || forbidden.has(s);

      const hardFeasible = !teacherBusy && !studentBusy && freeRoomCount > 0 && !forbiddenHit;
      const softFeasible = !teacherBusy && !studentBusy && freeRoomCount > 0; // forbidden ignored in soft pass

      results.push({ tk, teacherBusy, studentBusy, freeRoomCount, forbiddenHit, hardFeasible, softFeasible });
    }
  }

  const hard = results.filter(r => r.hardFeasible);
  const soft = results.filter(r => r.softFeasible);
  const blockers = {
    teacher_busy: results.filter(r => r.teacherBusy).length,
    student_busy: results.filter(r => r.studentBusy).length,
    no_room: results.filter(r => r.freeRoomCount === 0).length,
    forbidden: results.filter(r => r.forbiddenHit).length
  };

  console.log('Target', { section:'K26DG', course:'ENG101', teacher, students:students.length, placedSessions:targetRows.length, requiredSessions:2 });
  console.log('Hard feasible slots', hard.length);
  console.log('Soft feasible slots', soft.length);
  console.log('Blocker counts', blockers);
  console.log('Soft feasible sample', soft.slice(0,10).map(r=>({time:r.tk,freeRooms:r.freeRoomCount})));
})();
