import { SolverService } from './src/services/solverService';
import { supabase } from './src/config/supabase';

(async()=>{
  const s:any = new SolverService();
  await s.loadData();
  const sections:any[] = s.sections || s['sections'] || [];

  const { data: mt, error } = await supabase.from('master_timetable').select('course_code,section_name,time_slot');
  if (error) throw error;

  const actualCount = new Map<string, number>();
  for (const r of (mt||[])) {
    const k = `${r.section_name}__${r.course_code}`;
    actualCount.set(k, (actualCount.get(k) || 0) + 1);
  }

  const diffs = sections.map(sec => {
    const key = `${sec.sectionName}__${sec.courseId}`;
    const actual = actualCount.get(key) || 0;
    const expected = sec.sessionsPerWeek;
    return {
      id: sec.id,
      sectionName: sec.sectionName,
      courseId: sec.courseId,
      expected,
      actual,
      missing: Math.max(0, expected - actual),
      extra: Math.max(0, actual - expected),
      studentCount: (sec.enrolledStudents || []).length,
      groupingId: sec.groupingId,
      semester: sec.semester
    };
  });

  const missing = diffs.filter(d => d.missing > 0).sort((a,b)=>b.missing-a.missing);
  const extra = diffs.filter(d => d.extra > 0).sort((a,b)=>b.extra-a.extra);
  const totalMissing = missing.reduce((a,b)=>a+b.missing,0);
  const totalExtra = extra.reduce((a,b)=>a+b.extra,0);

  console.log('sections', sections.length);
  console.log('totalMissing', totalMissing, 'totalExtra', totalExtra);
  console.log('missingRows', JSON.stringify(missing.slice(0,10), null, 2));
})();
