  const targetRows = (mt || []).filter(r => r.section_name === sectionName && r.course_code === courseCode);

  const sections = solver.sections || solver['sections'] || [];
  const sec = sections.find(x => x.id === targetId);
  const studentIds = sec?.enrolledStudents || (targetRows[0]?.student_ids || []);
  const sessionsPerWeek = sec?.sessionsPerWeek;

  console.log('TARGET', JSON.stringify({ targetId, sectionName, courseCode, sessionsPerWeek, studentCount: studentIds.length, placedForTarget: targetRows.length }, null, 2));

  if (!targetRows.length) {
    console.log('No placed row for this target; cannot infer assigned teacher from timetable.');
    return;
  }

  const teacher = targetRows[0].instructor_name;
  const { data: faculty, error: e2 } = await supabase.from('faculty').select('name,forbidden_slots');
  if (e2) throw e2;
  const teacherRec = (faculty || []).find(f => f.name === teacher);
  const forbidden = new Set(Array.isArray(teacherRec?.forbidden_slots) ? teacherRec.forbidden_slots.map(String) : []);

  const { data: infra, error: e3 } = await supabase.from('infrastructure').select('room_id,room_type,capacity_lecture');
  if (e3) throw e3;
  const compatibleRooms = (infra || []).filter(r => !String(r.room_type || '').toLowerCase().includes('lab') && Number(r.capacity_lecture || 0) >= studentIds.length);

  const roomOcc = new Set();
  const teacherOcc = new Set();
  const studentOcc = new Set();
  for (const r of (mt || [])) {
    const tk = r.time_slot;
    roomOcc.add(`${r.room_id}|${tk}`);
    teacherOcc.add(`${r.instructor_name}|${tk}`);
    const sids = Array.isArray(r.student_ids) ? r.student_ids : [];
    for (const sid of sids) studentOcc.add(`${sid}|${tk}`);
  }

  const checks = [];
  for (const d of days) {
    for (const s of slots) {
      const tk = `${d} ${s}`;
      if (targetRows.some(r => r.time_slot === tk)) continue;
      const teacherBusy = teacherOcc.has(`${teacher}|${tk}`);
      let studentBusy = false;
      for (const sid of studentIds) {
        if (studentOcc.has(`${sid}|${tk}`)) { studentBusy = true; break; }
      }
      const freeRoomCount = compatibleRooms.filter(r => !roomOcc.has(`${r.room_id}|${tk}`)).length;
      const forbiddenHit = forbidden.has(tk) || forbidden.has(s);
      checks.push({ tk, teacherBusy, studentBusy, noRoom: freeRoomCount === 0, forbiddenHit, hardFeasible: !teacherBusy && !studentBusy && freeRoomCount > 0 && !forbiddenHit, softFeasible: !teacherBusy && !studentBusy && freeRoomCount > 0 });
    }
  }

  const hard = checks.filter(c => c.hardFeasible);
  const soft = checks.filter(c => c.softFeasible);
  const reasons = {
    teacher_busy: checks.filter(c => c.teacherBusy).length,
    student_busy: checks.filter(c => c.studentBusy).length,
    no_room: checks.filter(c => c.noRoom).length,
    forbidden: checks.filter(c => c.forbiddenHit).length
  };

  console.log('FEASIBILITY', JSON.stringify({ teacher, hardFeasible: hard.length, softFeasible: soft.length, reasons, softSamples: soft.slice(0, 8).map(x => x.tk) }, null, 2));
})();
