  for(const r of (mt||[])){
    const chunk=(Array.isArray(r.student_ids)?r.student_ids:[]).slice().sort();
    const stable=`${r.course_code}||${chunk.join(',')}`;
    actualCount.set(stable,(actualCount.get(stable)||0)+1);
  }

  const missing=[];
  let totalMissing=0;
  for(const [stable,exp] of expected.entries()){
    const actual=actualCount.get(stable)||0;
    const miss=Math.max(0,exp.expected-actual);
    if(miss>0){
      totalMissing+=miss;
      missing.push({course:exp.course, studentCount:exp.students.length, expected:exp.expected, actual, missing:miss, sampleStudents:exp.students.slice(0,5), cohort:exp.cohortKey});
    }
  }

  missing.sort((a,b)=>b.missing-a.missing);
  console.log('TOTAL_MISSING', totalMissing);
  console.log('MISSING_TOP', JSON.stringify(missing.slice(0,10),null,2));
})();
