require('dotenv').config();
const { createClient } = require('@supabase/supabase-js');
const supabase=createClient(process.env.SUPABASE_URL,process.env.SUPABASE_SERVICE_ROLE_KEY);

const slots=['09:00 AM - 09:50 AM','10:00 AM - 10:50 AM','11:00 AM - 11:50 AM','12:00 PM - 12:50 PM','01:10 PM - 02:00 PM','02:10 PM - 03:00 PM','03:10 PM - 04:00 PM','04:10 PM - 05:00 PM'];
const days=['Mon','Tue','Wed','Thu','Fri','Sat'];
const allTimes=days.flatMap(d=>slots.map(s=>`${d} ${s}`));

async function fetchAll(table, cols, orderBy){
  let rows=[], from=0, page=1000;
  while(true){
    let q=supabase.from(table).select(cols);
    if(orderBy) q=q.order(orderBy,{ascending:true});
    const {data,error}=await q.range(from,from+page-1);
    if(error) throw error;
    const b=data||[]; rows.push(...b);
    if(b.length<page) break;
    from+=page;
  }
  return rows;
}

(async()=>{
  const mt=await fetchAll('master_timetable','*','section_name');
  const engRows=mt.filter(r=>r.course_code==='ENG101');
  const target=engRows.find(r=>r.section_name==='K26DG') || engRows.find(r=>(Array.isArray(r.student_ids)?r.student_ids.length:0)===17);
  if(!target){ console.log('No ENG101 target section found'); return; }

  const students = Array.isArray(target.student_ids)?target.student_ids:[];
  const teacher = target.instructor_name;
  const placedTimesForSection = engRows.filter(r=>r.section_name===target.section_name).map(r=>r.time_slot);

  const studentBusy=new Set();
  for(const r of mt){
    const sids=Array.isArray(r.student_ids)?r.student_ids:[];
    for(const sid of sids){
      if(students.includes(sid)) studentBusy.add(r.time_slot);
    }
  }

  const teacherBusy=new Set(mt.filter(r=>r.instructor_name===teacher).map(r=>r.time_slot));

  const studentFree=allTimes.filter(t=>!studentBusy.has(t));
  const teacherFree=allTimes.filter(t=>!teacherBusy.has(t));
  const bothFree=allTimes.filter(t=>!studentBusy.has(t) && !teacherBusy.has(t));
  const bothFreeExcludingPlaced=bothFree.filter(t=>!placedTimesForSection.includes(t));

  console.log('Target section:', target.section_name, 'course:', target.course_code);
  console.log('Students:', students.length, 'Teacher:', teacher);
  console.log('Already placed times for this section:', JSON.stringify(placedTimesForSection));
  console.log('\nStudent free slots count:', studentFree.length);
  console.log(JSON.stringify(studentFree));
  console.log('\nTeacher free slots count:', teacherFree.length);
  console.log(JSON.stringify(teacherFree));
  console.log('\nBoth free slots count (including already-used section time):', bothFree.length);
  console.log(JSON.stringify(bothFree));
  console.log('\nBoth free slots for adding another session (excluding already-used section time):', bothFreeExcludingPlaced.length);
  console.log(JSON.stringify(bothFreeExcludingPlaced));

  const mappings = await fetchAll('teacher_subjects','teacher_id,course_id','teacher_id');
  const faculties = await fetchAll('faculty','teacher_id,name','teacher_id');
  const qualifiedIds = mappings.filter(m=>m.course_id==='ENG101').map(m=>m.teacher_id);
  const qualified = faculties.filter(f=>qualifiedIds.includes(f.teacher_id));

  console.log('\nQualified teachers for ENG101:', qualified.map(q=>q.name));
  for(const q of qualified){
    const tb=new Set(mt.filter(r=>r.instructor_name===q.name).map(r=>r.time_slot));
    const inter=allTimes.filter(t=>!tb.has(t) && !studentBusy.has(t) && !placedTimesForSection.includes(t));
    console.log(`Teacher ${q.name} -> shared free (new session) slots: ${inter.length}`);
  }
})();
